+    #[test]
+    fn validity_mask_count_invalid_matches_complement() {
+        let mask = ValidityMask::from_values(&[
+            Scalar::Int64(1),
+            Scalar::Null(NullKind::NaN),
+            Scalar::Int64(2),
+            Scalar::Null(NullKind::Null),
